#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int mod=2017,N=105;
int n,m,t,ans;
struct node
{
	int num[N][N];
} a,b;
node fun(node x,node y)
{
	node tmp;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++) tmp.num[i][j]=0;
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			for(int k=1;k<=n;k++)
			{
				tmp.num[j][k]+=((x.num[j][i]*y.num[i][k])%mod);
				tmp.num[j][k]%=mod;
			}
		}
	}
	return tmp;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	n++;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++) a.num[i][j]=b.num[i][j]=0;
	}
	for(int i=1;i<=m;i++)
	{
		int u,v;
		cin>>u>>v;
		a.num[u][v]=1;
		a.num[v][u]=1;
	}
	for(int i=1;i<=n;i++)
	{
		a.num[i][n]=a.num[i][i]=b.num[i][i]=1;
	}
	cin>>t;
	while(t)
	{
		if(t%2==1)
		{
			b=fun(b,a);
		}
		a=fun(a,a);
		t/=2;
	}
	for(int i=1;i<=n;i++)
	{
		ans=(b.num[1][i]+ans)%mod;
	}
	cout<<ans;
	return 0;
}
